import jwt
import base64

def decode_and_verify_jwt(token):
    try:
        headers_and_claims = jwt.decode(token, verify=True)
        print("Headers:", headers_and_claims['headers'])
        print("Claims:", headers_and_claims)
    except jwt.ExpiredSignatureError:
        print("The token has expired.")
    except jwt.JWTError:
        print("Invalid token signature.")